void testVariables() {
    // Basic declarations
    int a = 5;
    float b = 2.5f;
    double c(9.81);
    bool flag = true;
    char ch = 'A';
    std::string s = "Tree-sitter";

    // Pointer and reference
    int x = 10;
    int *p = &x;
    int &ref = x;
    const int *const_ptr = &x;

    // Arrays
    int nums[3] = {1, 2, 3};
    char letters[] = {'a', 'b', 'c'};
    std::string words[2] = {"hello", "world"};

    // Vector and auto type
    std::vector<int> vec = {1, 2, 3, 4};
    auto val = vec[2];

    // Structured bindings (C++17)
    Point pt = {10, 20};
    auto [px, py] = pt;

    // Assignments and compound ops
    a = 10;
    a += 5;
    b *= 3.0f;
    c /= 2;
    flag = !flag;
    s += " test";
    x = a + b - c;

    // Expressions and function calls
    std::cout << "Sum: " << (a + b + c) << std::endl;

    // Dynamic allocation
    int *dyn = new int(99);
    delete dyn;

    // Static and const local variables
    static int counter = 0;
    const double PI = 3.14159;

    // Lambda with captured variable
    auto lambda = [=]() { return PI * a; };
    double result = lambda();

    // Object and member assignments
    Demo d;
    d.member = 50;
    d.setMember(25);
    Demo::static_member = 200;
}

